        var pool = filteredIndices.slice();
        for (var si2 = pool.length - 1; si2 > 0; si2--) { var sj = Math.floor(rng() * (si2 + 1)); var st = pool[si2]; pool[si2] = pool[sj]; pool[sj] = st; }
        sampled = pool.slice(0, Math.min(counts.total, pool.length));
